sys.setrecursionlimit(100000)

memo={}
def has_bpawn(b):
    return any(b.piece_at(s) and b.piece_at(s).color==chess.BLACK and b.piece_type_at(s)==chess.PAWN for s in chess.SQUARES)
def has_bqueen(b):
    return any(b.piece_at(s) and b.piece_at(s).color==chess.BLACK and b.piece_type_at(s)==chess.QUEEN for s in chess.SQUARES)

def solve(b, depth):
    k=(b.fen(),depth)
    if k in memo: return memo[k]
    if not has_bpawn(b):
        memo[k]=(1,0); return (1,0)
    if has_bqueen(b):
        memo[k]=(-1,0); return (-1,0)
    if b.is_stalemate():
        memo[k]=(0,0); return (0,0)
    if b.is_checkmate():
        memo[k]=((-1,0) if b.turn==chess.WHITE else (1,0)); return memo[k]
    if depth==0:
        memo[k]=(0,0); return (0,0)
    res=[]
    for m in b.legal_moves:
        b.push(m); w,d=solve(b,depth-1); b.pop()
        res.append((w,d+1,m))
    if b.turn==chess.WHITE:
        wins=[r for r in res if r[0]==1]
        if wins:
            best=min(wins,key=lambda r:r[1]); memo[k]=(1,best[1])
        else:
            draws=[r for r in res if r[0]==0]
            memo[k]=(0,0) if draws else (-1,0)
    else:
        winsb=[r for r in res if r[0]==-1]
        draws=[r for r in res if r[0]==0]
        losses=[r for r in res if r[0]==1]
        if winsb: memo[k]=(-1,0)
        elif draws: memo[k]=(0,0)
        else:
            best=max(losses,key=lambda r:r[1]); memo[k]=(1,best[1])
    return memo[k]

def pv(b, depth):
    out=[]; bb=b.copy()
    while True:
        if not has_bpawn(bb) or bb.is_game_over(): break
        choices=[]
        for m in bb.legal_moves:
            bb.push(m); ww,dd=solve(bb,depth-1); bb.pop()
            choices.append((ww,dd,m))
        if bb.turn==chess.WHITE:
            wins=[c for c in choices if c[0]==1]
            m=min(wins,key=lambda c:c[1])[2] if wins else choices[0][2]
        else:
            losses=[c for c in choices if c[0]==1]
            m=max(losses,key=lambda c:c[1])[2] if losses else choices[0][2]
        out.append(bb.san(m)); bb.push(m)
        if len(out)>34: break
